import{pipe,asyncMap,asyncCollectArray}from"@hyperjump/pact";import*as Schema from"../schema.js";import*as Instance from"../instance.js";const id="https://json-schema.org/keyword/dependentRequired",compile=e=>pipe(Schema.entries(e),asyncMap(([e,t])=>[e,Schema.value(t)]),asyncCollectArray),interpret=(e,t)=>{const r=Instance.value(t);return!Instance.typeOf(t,"object")||e.every(([e,t])=>!(e in r)||t.every(e=>e in r))};export default{id:id,compile:compile,interpret:interpret};